"use client";

import { FormEvent, useEffect, useState } from "react";

type Property = {
  id: string;
  title: string;
  type: string;
  location: string;
  price: string;
  status: string;
  imageUrl: string;
  description: string;
};

type PropertyFormState = {
  title: string;
  type: string;
  location: string;
  price: string;
  status: string;
  imageUrl: string;
  description: string;
};

const initialFormState: PropertyFormState = {
  title: "",
  type: "",
  location: "",
  price: "",
  status: "new launch",
  imageUrl: "",
  description: "",
};

export default function AddPropertySection() {
  const [form, setForm] = useState<PropertyFormState>(initialFormState);
  const [properties, setProperties] = useState<Property[]>([]);
  const [submitting, setSubmitting] = useState(false);
  const [message, setMessage] = useState("");

  useEffect(() => {
    async function loadProperties() {
      const response = await fetch("/api/properties", { cache: "no-store" });
      if (!response.ok) {
        return;
      }
      const data = (await response.json()) as { properties: Property[] };
      setProperties(data.properties);
    }

    void loadProperties();
  }, []);

  async function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setSubmitting(true);
    setMessage("");

    const response = await fetch("/api/properties", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(form),
    });

    const data = (await response.json()) as {
      property?: Property;
      error?: string;
    };

    if (!response.ok || !data.property) {
      setMessage(data.error ?? "Could not add property.");
      setSubmitting(false);
      return;
    }

    setProperties((prev) => [data.property as Property, ...prev]);
    setForm(initialFormState);
    setMessage("Property added successfully.");
    setSubmitting(false);
  }

  return (
    <section className="mx-auto mt-10 mb-16 w-full max-w-7xl px-4 md:px-6">
      <div className="rounded-2xl border border-zinc-200 bg-white p-6 shadow-sm">
        <h2 className="text-2xl font-semibold text-zinc-900">Add Property</h2>
        <p className="mt-2 text-sm text-zinc-600">
          This section is connected to backend `POST /api/properties`.
        </p>

        <form onSubmit={handleSubmit} className="mt-6 grid gap-3 md:grid-cols-2">
          <input
            value={form.title}
            onChange={(event) => setForm((prev) => ({ ...prev, title: event.target.value }))}
            placeholder="Property title"
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            required
          />
          <input
            value={form.type}
            onChange={(event) => setForm((prev) => ({ ...prev, type: event.target.value }))}
            placeholder="Property type"
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            required
          />
          <input
            value={form.location}
            onChange={(event) =>
              setForm((prev) => ({ ...prev, location: event.target.value }))
            }
            placeholder="Location"
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            required
          />
          <input
            value={form.price}
            onChange={(event) => setForm((prev) => ({ ...prev, price: event.target.value }))}
            placeholder="Price (example: INR 1.2 Cr)"
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            required
          />
          <input
            value={form.status}
            onChange={(event) => setForm((prev) => ({ ...prev, status: event.target.value }))}
            placeholder="Status"
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
          />
          <input
            value={form.imageUrl}
            onChange={(event) =>
              setForm((prev) => ({ ...prev, imageUrl: event.target.value }))
            }
            placeholder="Image URL (optional)"
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
          />
          <textarea
            value={form.description}
            onChange={(event) =>
              setForm((prev) => ({ ...prev, description: event.target.value }))
            }
            placeholder="Description"
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm md:col-span-2"
            rows={3}
          />
          <button
            type="submit"
            disabled={submitting}
            className="md:col-span-2 rounded-lg bg-zinc-900 px-4 py-2 text-sm font-semibold text-white transition hover:bg-zinc-700 disabled:cursor-not-allowed disabled:opacity-70"
          >
            {submitting ? "Adding..." : "Add Property"}
          </button>
        </form>

        {message ? <p className="mt-3 text-sm text-zinc-700">{message}</p> : null}
      </div>

      <div className="mt-6 grid gap-3 md:grid-cols-2">
        {properties.slice(0, 6).map((property) => (
          <article
            key={property.id}
            className="rounded-xl border border-zinc-200 bg-zinc-50 p-4"
          >
            <p className="text-xs font-semibold uppercase tracking-wide text-zinc-500">
              {property.status}
            </p>
            <h3 className="mt-1 text-lg font-semibold text-zinc-900">{property.title}</h3>
            <p className="mt-1 text-sm text-zinc-600">
              {property.type} - {property.location}
            </p>
            <p className="mt-2 text-sm font-medium text-zinc-900">{property.price}</p>
          </article>
        ))}
      </div>
    </section>
  );
}
